/// <reference lib="webworker" />

declare const self: ServiceWorkerGlobalScope

import { precacheAndRoute } from 'workbox-precaching'

// Precache all assets generated by Vite
precacheAndRoute(self.__WB_MANIFEST)

// Background sync for offline captures
self.addEventListener('sync', (event: any) => {
  if (event.tag === 'sync-offline-captures') {
    event.waitUntil(syncOfflineCaptures())
  }
})

async function syncOfflineCaptures() {
  // Get offline captures from IndexedDB
  const db = await openDB()
  const tx = db.transaction('offline', 'readonly')
  const store = tx.objectStore('offline')
  const captures = await getAll(store)

  for (const capture of captures) {
    try {
      const response = await fetch('/v1/capture', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Khayal-Token': capture.token || '',
        },
        body: JSON.stringify(capture.request),
      })

      if (response.ok) {
        // Remove from offline store on success
        const deleteTx = db.transaction('offline', 'readwrite')
        const deleteStore = deleteTx.objectStore('offline')
        await deleteStore.delete(capture.id)
      }
    } catch {
      // Will retry on next sync
    }
  }
}

// IndexedDB helpers
async function openDB(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open('khayal-offline', 1)
    request.onerror = () => reject(request.error)
    request.onsuccess = () => resolve(request.result)
    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result
      if (!db.objectStoreNames.contains('offline')) {
        db.createObjectStore('offline', { keyPath: 'id' })
      }
    }
  })
}

async function getAll(store: IDBObjectStore): Promise<any[]> {
  return new Promise((resolve, reject) => {
    const request = store.getAll()
    request.onerror = () => reject(request.error)
    request.onsuccess = () => resolve(request.result)
  })
}

// Push notification handler
self.addEventListener('push', (event: any) => {
  if (!event.data) return

  const data = event.data.json()
  const options: NotificationOptions = {
    body: data.body,
    icon: '/icon-192.png',
    badge: '/icon-192.png',
    data: data.url,
  }

  event.waitUntil(self.registration.showNotification(data.title, options))
})

// Notification click handler
self.addEventListener('notificationclick', (event: any) => {
  event.notification.close()
  if (event.notification.data) {
    event.waitUntil(self.clients.openWindow(event.notification.data))
  }
})

// Message handler for manual sync trigger
self.addEventListener('message', (event: any) => {
  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting()
  }
  if (event.data && event.data.type === 'SYNC_OFFLINE') {
    syncOfflineCaptures()
  }
})

// Activate immediately
self.addEventListener('activate', (event: any) => {
  event.waitUntil(self.clients.claim())
})
